import{_ as t,c as l,o as e,V as s}from"./chunks/framework.35c8bad0.js";const f=JSON.parse('{"title":"面试题[微前端]","description":"","frontmatter":{"title":"面试题[微前端]","date":"2024-01-31T00:00:00.000Z"},"headers":[],"relativePath":"blog/interview/240131.md","lastUpdated":1779956915000}'),a={name:"blog/interview/240131.md"},n=s(`<h1 id="面试题-微前端" tabindex="-1">面试题[微前端] <a class="header-anchor" href="#面试题-微前端" aria-label="Permalink to &quot;面试题[微前端]&quot;">​</a></h1><h2 id="_1-微前端基础" tabindex="-1">1. 微前端基础 <a class="header-anchor" href="#_1-微前端基础" aria-label="Permalink to &quot;1. 微前端基础&quot;">​</a></h2><h3 id="_1-1-什么是微前端" tabindex="-1">1.1 什么是微前端 <a class="header-anchor" href="#_1-1-什么是微前端" aria-label="Permalink to &quot;1.1 什么是微前端&quot;">​</a></h3><p>微前端（Micro-frontend）是一种将后端微服务理念扩展到前端的架构模式，其核心思想是“分而治之”——将大型前端应用拆分为多个独立的小型子应用，每个子应用可独立开发、测试、部署，最终在浏览器中集成运行。微前端借鉴了微服务的架构理念，将微服务的概念扩展到了前端。</p><h3 id="_1-2-为什么需要微前端-解决了什么问题" tabindex="-1">1.2 为什么需要微前端 / 解决了什么问题 <a class="header-anchor" href="#_1-2-为什么需要微前端-解决了什么问题" aria-label="Permalink to &quot;1.2 为什么需要微前端 / 解决了什么问题&quot;">​</a></h3><p>传统单体架构在大规模前端应用中逐渐暴露三大痛点：</p><ul><li><strong>协作效率低下</strong>：多团队并行开发时，代码冲突、依赖冲突频繁发生，构建部署耗时超过30分钟成为常态。</li><li><strong>技术栈绑定</strong>：统一技术栈限制了团队创新空间，新框架引入成本高。</li><li><strong>部署风险集中</strong>：任意模块的代码变更都需全量发布，影响整体稳定性。</li></ul><p>微前端架构通过“分而治之”的治理模式，实现独立开发、独立部署、故障隔离和弹性扩展四大核心价值。据2025年行业调研显示，采用微前端架构的企业平均提升40%的研发效率，降低35%的运维成本。</p><h3 id="_1-3-微前端适合什么场景" tabindex="-1">1.3 微前端适合什么场景 <a class="header-anchor" href="#_1-3-微前端适合什么场景" aria-label="Permalink to &quot;1.3 微前端适合什么场景&quot;">​</a></h3><p>适合的场景：</p><ul><li>跨团队协作的大型网站（如电商平台、企业管理系统）</li><li>需整合遗留系统与新功能的迭代型项目</li><li>要求高频发布且需保障系统稳定性的业务平台（如金融科技网站、在线教育平台）</li><li>子应用数量超过5个以上的大型项目</li></ul><p>不适合的场景：小型、简单的项目，使用微前端是“杀鸡用牛刀”，反而会增加维护成本。</p><h3 id="_1-4-主流框架对比" tabindex="-1">1.4 主流框架对比 <a class="header-anchor" href="#_1-4-主流框架对比" aria-label="Permalink to &quot;1.4 主流框架对比&quot;">​</a></h3><p><strong>主流框架概况</strong></p><table><thead><tr><th style="text-align:left;">框架</th><th style="text-align:left;">开发公司</th><th style="text-align:left;">核心技术</th><th style="text-align:left;">首次发布</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>qiankun（乾坤）</strong></td><td style="text-align:left;">蚂蚁集团</td><td style="text-align:left;">基于Single-SPA + Proxy沙箱</td><td style="text-align:left;">2019.08</td></tr><tr><td style="text-align:left;"><strong>wujie（无界）</strong></td><td style="text-align:left;">腾讯</td><td style="text-align:left;">iframe + Proxy沙箱</td><td style="text-align:left;">2022.03</td></tr><tr><td style="text-align:left;"><strong>micro-app</strong></td><td style="text-align:left;">京东</td><td style="text-align:left;">WebComponents + Shadow DOM</td><td style="text-align:left;">2021.04</td></tr><tr><td style="text-align:left;"><strong>single-spa</strong></td><td style="text-align:left;">社区驱动</td><td style="text-align:left;">路由劫持 + 生命周期</td><td style="text-align:left;">2018.01</td></tr><tr><td style="text-align:left;"><strong>Module Federation</strong></td><td style="text-align:left;">Webpack5</td><td style="text-align:left;">构建时模块联邦</td><td style="text-align:left;">2020</td></tr></tbody></table><p><strong>核心能力对比</strong></p><table><thead><tr><th style="text-align:left;">能力</th><th style="text-align:left;">qiankun</th><th style="text-align:left;">wujie</th><th style="text-align:left;">micro-app</th><th style="text-align:left;">single-spa</th></tr></thead><tbody><tr><td style="text-align:left;">沙箱隔离</td><td style="text-align:left;">Proxy+快照沙箱</td><td style="text-align:left;">iframe原生隔离</td><td style="text-align:left;">Shadow DOM / 代理沙箱</td><td style="text-align:left;">需手动实现</td></tr><tr><td style="text-align:left;">通信机制</td><td style="text-align:left;">props + globalState + 事件</td><td style="text-align:left;">props + window通信 + postMessage</td><td style="text-align:left;">数据通信 + 事件总线</td><td style="text-align:left;">自定义实现</td></tr><tr><td style="text-align:left;">子应用保活</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">多应用同时激活</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td></tr><tr><td style="text-align:left;">上手难度</td><td style="text-align:left;">中等</td><td style="text-align:left;">简单</td><td style="text-align:left;">简单</td><td style="text-align:left;">困难</td></tr><tr><td style="text-align:left;">Vite兼容性</td><td style="text-align:left;">需插件</td><td style="text-align:left;">原生支持</td><td style="text-align:left;">原生支持</td><td style="text-align:left;">需适配</td></tr><tr><td style="text-align:left;">隔离安全性</td><td style="text-align:left;">高</td><td style="text-align:left;">极高</td><td style="text-align:left;">高</td><td style="text-align:left;">低</td></tr></tbody></table><blockquote><p>⚠️ 注意：qiankun在2024年后维护频率明显下降（近6个月commit次数为0），选型时需关注社区活跃度。</p></blockquote><p><strong>各框架优缺点</strong></p><p><strong>qiankun（乾坤）</strong>：</p><ul><li>优点：成熟稳定、经过大规模生产验证、沙箱机制完善</li><li>缺点：侵入性较强、沙箱有性能开销、社区维护放缓</li><li>适用场景：大型企业级应用、混合技术栈迁移、对隔离性要求较高</li></ul><p><strong>wujie（无界）</strong>：</p><ul><li>优点：原生隔离、轻量级、低侵入性、支持保活</li><li>缺点：iframe性能开销较大、功能相对局限</li><li>适用场景：高安全需求场景、嵌入第三方页面、需要子应用保活</li></ul><p><strong>micro-app</strong>：</p><ul><li>优点：组件化接入、低成本接入、性能优异</li><li>缺点：生态相对较小、部分UI库不兼容Shadow DOM</li><li>适用场景：快速集成、跨团队协作、移动端兼容</li></ul><h3 id="_1-5-在微前端技术选型的时候是如何考虑的" tabindex="-1">1.5 在微前端技术选型的时候是如何考虑的 <a class="header-anchor" href="#_1-5-在微前端技术选型的时候是如何考虑的" aria-label="Permalink to &quot;1.5 在微前端技术选型的时候是如何考虑的&quot;">​</a></h3><h3 id="_1-6-在子应用单独启动的情况下-怎么获取主应用的-cookie-信息" tabindex="-1">1.6 在子应用单独启动的情况下，怎么获取主应用的 cookie 信息 <a class="header-anchor" href="#_1-6-在子应用单独启动的情况下-怎么获取主应用的-cookie-信息" aria-label="Permalink to &quot;1.6 在子应用单独启动的情况下，怎么获取主应用的 cookie 信息&quot;">​</a></h3><p>在子应用单独启动的情况下，要获取主应用的cookie信息，通常需要进行跨域访问，并且主应用需要开放相应的跨域访问权限。具体方法如下：</p><ol><li><strong>跨域访问设置</strong>：主应用需要配置允许跨域访问的策略，通常是通过设置CORS（跨源资源共享）策略来实现。可以在主应用的服务器端配置Access-Control-Allow-Origin头部，允许子应用的域名进行跨域访问。</li><li><strong>在子应用中发送请求</strong>：子应用可以通过发送HTTP请求到主应用的服务器来获取cookie信息。这可以是一个简单的GET请求，或者使用XMLHttpRequest、Fetch API等技术。</li><li><strong>处理响应</strong>：主应用服务器收到子应用发送的请求后，如果已经配置了允许跨域访问，会将响应发送给子应用。子应用可以从响应中获取到主应用的cookie信息。</li><li><strong>处理Cookie</strong>：在子应用中接收到主应用的响应后，可以通过相应的方式获取cookie信息，例如，使用Document.cookie属性来获取cookie信息。</li></ol><p>需要注意的是，获取主应用的cookie信息可能涉及到安全性和隐私问题，需要确保获取cookie的操作是合法且安全的，同时用户需要明确同意共享这些信息。</p><h2 id="_2-微前端进阶" tabindex="-1">2. 微前端进阶 <a class="header-anchor" href="#_2-微前端进阶" aria-label="Permalink to &quot;2. 微前端进阶&quot;">​</a></h2><h3 id="_2-1-微前端需要解决哪些核心问题" tabindex="-1">2.1 微前端需要解决哪些核心问题 <a class="header-anchor" href="#_2-1-微前端需要解决哪些核心问题" aria-label="Permalink to &quot;2.1 微前端需要解决哪些核心问题&quot;">​</a></h3><p>主要需解决四大关键问题：</p><table><thead><tr><th style="text-align:left;">核心问题</th><th style="text-align:left;">具体内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>JS隔离（沙箱）</strong></td><td style="text-align:left;">防止子应用间的全局变量污染（不同子应用可能依赖不同版本的Vue/React）</td></tr><tr><td style="text-align:left;"><strong>CSS隔离（样式隔离）</strong></td><td style="text-align:left;">防止不同子应用的样式相互干扰、覆盖</td></tr><tr><td style="text-align:left;"><strong>路由管理</strong></td><td style="text-align:left;">子应用路由与主应用路由的协调、嵌套路由支持</td></tr><tr><td style="text-align:left;"><strong>跨应用通信</strong></td><td style="text-align:left;">主/子应用之间、子应用之间的数据共享与事件传递</td></tr></tbody></table><h4 id="js隔离的原理与实现方案" tabindex="-1">JS隔离的原理与实现方案 <a class="header-anchor" href="#js隔离的原理与实现方案" aria-label="Permalink to &quot;JS隔离的原理与实现方案&quot;">​</a></h4><p>微前端场景中，不同子应用可能依赖不同版本的Vue/React，甚至会修改window上的全局变量（如Vue、$）。若不做隔离，子应用A的修改会覆盖子应用B的全局变量，导致功能异常。</p><p>常见的JS隔离方案有：</p><p><strong>① 快照沙箱（SnapshotSandbox）</strong></p><ul><li>原理：子应用挂载前给window拍“快照”，卸载时根据快照恢复window状态</li><li>实现：挂载前遍历window保存所有属性的初始值；卸载时新增属性直接删除，修改属性还原为初始值</li><li>优点：逻辑简单；缺点：需全量遍历window性能较差，同一时间只能运行一个子应用</li></ul><p><strong>② Proxy沙箱（ProxySandbox）</strong></p><ul><li>原理：为每个子应用创建独立的<code>fakeWindow</code>，通过Proxy代理对window的访问</li><li>实现：<code>get</code>拦截从fakeWindow优先读取，<code>set</code>拦截写入fakeWindow而非真实window</li><li>优点：真正的环境隔离；缺点：Proxy无法完全代理所有window操作</li></ul><p><strong>③ iframe原生隔离</strong></p><ul><li>原理：完全独立的浏览器上下文，天然隔离</li><li>优点：隔离性最强、安全性高；缺点：性能开销较大，通信复杂</li></ul><h4 id="css样式隔离的原理与实现方案" tabindex="-1">CSS样式隔离的原理与实现方案 <a class="header-anchor" href="#css样式隔离的原理与实现方案" aria-label="Permalink to &quot;CSS样式隔离的原理与实现方案&quot;">​</a></h4><p>由于CSS的全局性，不同子应用之间的样式可能会相互干扰。主流方案包括：</p><table><thead><tr><th style="text-align:left;">方案</th><th style="text-align:left;">原理</th><th style="text-align:left;">优缺点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>CSS命名空间</strong></td><td style="text-align:left;">为子应用的CSS类名添加唯一前缀（如<code>.app-prefix-btn</code>）</td><td style="text-align:left;">兼容性好；子应用内部仍可能相互影响</td></tr><tr><td style="text-align:left;"><strong>Shadow DOM</strong></td><td style="text-align:left;">浏览器原生API，将子应用DOM和样式封装在隔离环境中</td><td style="text-align:left;">隔离彻底；部分UI库不兼容，样式穿透困难</td></tr><tr><td style="text-align:left;"><strong>动态样式表</strong></td><td style="text-align:left;">子应用加载时动态添加style标签，卸载时移除</td><td style="text-align:left;">灵活可控；切换时可能有闪烁</td></tr></tbody></table><h4 id="主子应用如何通信" tabindex="-1">主子应用如何通信 <a class="header-anchor" href="#主子应用如何通信" aria-label="Permalink to &quot;主子应用如何通信&quot;">​</a></h4><p>主要有以下几种通信方式：</p><table><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">说明</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Props传递</strong></td><td style="text-align:left;">主应用通过props向子应用传递数据</td><td style="text-align:left;">简单数据传递</td></tr><tr><td style="text-align:left;"><strong>全局状态管理（initGlobalState）</strong></td><td style="text-align:left;">qiankun提供的全局状态池，支持跨应用状态共享</td><td style="text-align:left;">复杂状态共享、跨子应用数据同步</td></tr><tr><td style="text-align:left;"><strong>自定义事件</strong></td><td style="text-align:left;">基于<code>window.addEventListener/dispatchEvent</code></td><td style="text-align:left;">松散耦合的事件通知</td></tr><tr><td style="text-align:left;"><strong>postMessage / BroadcastChannel</strong></td><td style="text-align:left;">利用HTML5通信API</td><td style="text-align:left;">iframe方案下跨窗口通信</td></tr><tr><td style="text-align:left;"><strong>共享状态（Redux/Vuex）</strong></td><td style="text-align:left;">通过共享的状态管理库实现</td><td style="text-align:left;">统一技术栈的项目</td></tr></tbody></table><h4 id="路由冲突如何解决" tabindex="-1">路由冲突如何解决 <a class="header-anchor" href="#路由冲突如何解决" aria-label="Permalink to &quot;路由冲突如何解决&quot;">​</a></h4><p>微前端中，主子应用各自维护路由实例。解决方案：</p><ul><li>主应用监听history变化，匹配激活规则决定加载哪个子应用</li><li>子应用的路由基于基座应用的URL路径前缀进行匹配</li><li>采用路径前缀隔离策略：主应用路由<code>/app1/*</code>、<code>/app2/*</code>分别对应不同子应用</li></ul><h4 id="生命周期管理" tabindex="-1">生命周期管理 <a class="header-anchor" href="#生命周期管理" aria-label="Permalink to &quot;生命周期管理&quot;">​</a></h4><p>需定义标准化的生命周期钩子，主应用统一调度子应用的启动、挂载、卸载：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#A6ACCD;"> lifecycle </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#82AAFF;">bootstrap</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">props</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">// 初始化</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#82AAFF;">mount</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">props</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Promise</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;">      </span><span style="color:#676E95;font-style:italic;">// 挂载</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#82AAFF;">unmount</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;font-style:italic;">props</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">=&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Promise</span><span style="color:#A6ACCD;">     </span><span style="color:#676E95;font-style:italic;">// 卸载</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="_3-qiankun" tabindex="-1">3. qiankun <a class="header-anchor" href="#_3-qiankun" aria-label="Permalink to &quot;3. qiankun&quot;">​</a></h2><h3 id="_3-1-为什么选择-qiankun" tabindex="-1">3.1 为什么选择 qiankun <a class="header-anchor" href="#_3-1-为什么选择-qiankun" aria-label="Permalink to &quot;3.1 为什么选择 qiankun&quot;">​</a></h3><h3 id="_3-2-qiankun-的原理" tabindex="-1">3.2 qiankun 的原理 <a class="header-anchor" href="#_3-2-qiankun-的原理" aria-label="Permalink to &quot;3.2 qiankun 的原理&quot;">​</a></h3><h3 id="_3-3-qiankun-的微应用加载方案" tabindex="-1">3.3 qiankun 的微应用加载方案 <a class="header-anchor" href="#_3-3-qiankun-的微应用加载方案" aria-label="Permalink to &quot;3.3 qiankun 的微应用加载方案&quot;">​</a></h3><p>qiankun 的微应用加载方案是其架构的核心，精髓在于通过<strong>HTML Entry</strong>解决了传统方案的痛点，并基于此实现了一套高效的加载与隔离机制。</p><p>它替代了 single-spa 的 <strong>JS Entry</strong>，允许你直接提供一个子应用的HTML地址作为入口。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#82AAFF;">registerMicroApps</span><span style="color:#A6ACCD;">([</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">name</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">app react</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">entry</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">//localhost:7100</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// 直接提供一个HTML地址</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">container</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">#subapp-container</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#F07178;">activeRule</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">/app-react</span><span style="color:#89DDFF;">&#39;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">])</span><span style="color:#89DDFF;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这样做有两个很明显的好处：</p><ul><li><strong>接入更自然</strong>：直接提供HTML入口，无需关心JS文件打包的哈希名变化，避免主应用配置频繁变更。</li><li><strong>体验更完整</strong>：保持了子应用原有的优化能力，比如<strong>按需加载、CSS独立打包</strong>等都能保留。</li></ul><h4 id="核心加载器-import-html-entry" tabindex="-1">核心加载器：<code>import-html-entry</code> <a class="header-anchor" href="#核心加载器-import-html-entry" aria-label="Permalink to &quot;核心加载器：\`import-html-entry\`&quot;">​</a></h4><p>要实现HTML Entry，qiankun封装了专门解析HTML的库：<strong><code>import-html-entry</code></strong>。<code>import-html-entry</code> 的核心任务是将一个HTML地址，转化为一个可执行的子应用：</p><ol><li><strong>获取与解析</strong>：通过 <code>fetch</code> 获取子应用入口HTML文件内容。</li><li><strong>资源分离</strong>：使用正则表达式解析HTML，将内容分解为三部分： <ul><li><code>template</code>：处理后的HTML结构。</li><li><code>scripts</code>：所有内联和外部引用的JavaScript脚本。</li><li><code>styles</code>：所有内联和外部引用的CSS样式。</li></ul></li><li><strong>处理样式</strong>：将所有获取到的CSS（无论是内联还是外部链接）转换为<code>&lt;style&gt;</code>标签并内联进<code>template</code>。</li><li><strong>准备脚本</strong>：通过<code>getExternalScripts</code>获取所有JS文件的文本内容。</li><li><strong>执行脚本</strong>：通过<code>execScripts</code>在沙箱环境中按顺序执行JS代码，从而获取子应用导出的<code>bootstrap</code>, <code>mount</code>, <code>unmount</code>等生命周期函数。</li></ol><h4 id="微应用加载的具体流程" tabindex="-1">微应用加载的具体流程 <a class="header-anchor" href="#微应用加载的具体流程" aria-label="Permalink to &quot;微应用加载的具体流程&quot;">​</a></h4><p>整个过程在<code>loadApp</code>方法中被串联起来：</p><ol><li><strong>触发</strong>：URL的变化匹配到预设规则，触发子应用的加载。</li><li><strong>加载</strong>：调用<code>import-html-entry</code>获取资源模板与生命周期函数。</li><li><strong>隔离</strong>：创建JS沙箱和CSS隔离环境，防止应用间相互干扰。</li><li><strong>挂载</strong>：将处理后的<code>template</code>挂载到指定的DOM容器中，依次调用<code>bootstrap</code>和<code>mount</code>生命周期函数。</li><li><strong>缓存</strong>：资源会被缓存，再次加载时速度将大幅提升。</li></ol><h4 id="预加载与性能优化" tabindex="-1">预加载与性能优化 <a class="header-anchor" href="#预加载与性能优化" aria-label="Permalink to &quot;预加载与性能优化&quot;">​</a></h4><p>为了优化切换体验，qiankun 提供了智能的预加载机制。默认策略是<strong>懒加载</strong>，即只在用户首次访问时加载对应子应用资源。</p><p>你也可以在主应用启动时，通过<code>start</code>方法的<code>prefetch</code>属性开启预加载：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#82AAFF;">start</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">prefetch</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// 默认行为：在第一个子应用加载完成后，利用空闲时间预加载其他应用[reference:18]</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;font-style:italic;">// prefetch: &#39;all&#39;, // 启动后立即预加载所有应用[reference:19]</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;font-style:italic;">// prefetch: [&#39;app1&#39;, &#39;app2&#39;], // 只预加载指定的应用[reference:20]</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>沙箱方面，qiankun 提供了三代演进方案：</p><ul><li><strong>快照沙箱（SnapshotSandbox）</strong>：最早版本，性能较差，仅用于兼容旧浏览器。</li><li><strong>单应用代理沙箱（LegacySandbox）</strong>：性能得到优化，但存在全局污染，同一时刻只能激活一个子应用。</li><li><strong>多应用代理沙箱（ProxySandbox）</strong>：当前默认且最先进的方案。为每个子应用创建独立的虚拟<code>window</code>对象，实现真正的多实例共存，互不干扰。</li></ul><h3 id="_3-4-qiankun-的-javascript-沙箱原理" tabindex="-1">3.4 qiankun 的 JavaScript 沙箱原理 <a class="header-anchor" href="#_3-4-qiankun-的-javascript-沙箱原理" aria-label="Permalink to &quot;3.4 qiankun 的 JavaScript 沙箱原理&quot;">​</a></h3><p>JavaScript 沙箱：从“快照”到“代理”的演进。qiankun 的 JS 沙箱策略经历了三代演进，其核心矛盾在于如何在<strong>兼容性</strong>、<strong>隔离性</strong>和<strong>性能</strong>之间找到最佳平衡。当前版本会自动检测浏览器环境，在不支持 Proxy 时降级为快照沙箱。</p><table><thead><tr><th style="text-align:left;">演进阶段</th><th style="text-align:left;">核心技术与适用场景</th><th style="text-align:left;">优点</th><th style="text-align:left;">缺点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>快照沙箱</strong> (SnapshotSandbox)</td><td style="text-align:left;">无差别“复制-粘贴”，兼容所有浏览器</td><td style="text-align:left;">- 原理简单 - 兼容性好</td><td style="text-align:left;">- 性能差（全量遍历） - 仅支持单例</td></tr><tr><td style="text-align:left;"><strong>单例代理沙箱</strong> (LegacySandbox)</td><td style="text-align:left;">只记录变更，基于Proxy实现</td><td style="text-align:left;">- 性能优化，无需全量遍历</td><td style="text-align:left;">- 存在全局污染风险 - 仅支持单例</td></tr><tr><td style="text-align:left;"><strong>多例代理沙箱</strong> (ProxySandbox)</td><td style="text-align:left;">每个应用一个虚拟 Window 对象</td><td style="text-align:left;">- 真正意义的隔离 - 支持多实例</td><td style="text-align:left;">- 不兼容旧浏览器</td></tr></tbody></table><h3 id="_3-5-qiankun-的-css-沙箱原理" tabindex="-1">3.5 qiankun 的 CSS 沙箱原理 <a class="header-anchor" href="#_3-5-qiankun-的-css-沙箱原理" aria-label="Permalink to &quot;3.5 qiankun 的 CSS 沙箱原理&quot;">​</a></h3><p>CSS 沙箱：默认隔离与两种加强方案。qiankun 的 CSS 沙箱默认是自动开启的，其设计兼顾了开箱即用和灵活可控。</p><ol><li><strong>基础：动态样式隔离（默认开启）</strong><ul><li><strong>原理</strong>：利用 <code>import-html-entry</code> 解析子应用的 HTML 和 CSS，在卸载子应用时，主动移除其注入的所有样式表，保证应用切换时样式环境干净。</li><li><strong>局限</strong>：仅保证<strong>子应用间</strong>的样式互不影响，但无法完全隔离<strong>主子应用之间</strong>的样式冲突。</li></ul></li><li><strong>加强方案 1：严格样式隔离（strictStyleIsolation）</strong><ul><li><strong>实现</strong>：通过 <code>strictStyleIsolation: true</code> 开启，将整个子应用挂载到一个 <strong>Shadow DOM</strong> 节点下。</li><li><strong>原理</strong>：Shadow DOM 样式天然隔离，CSS 选择器无法穿透，是浏览器级别的隔离方案。</li><li><strong>代价</strong>：可能引发第三方 UI 库弹窗（如 Ant Design）找不到 body 而样式错乱等兼容性问题。</li></ul></li><li><strong>加强方案 2：实验性作用域沙箱（experimentalStyleIsolation）</strong><ul><li><strong>实现</strong>：通过 <code>experimentalStyleIsolation: true</code> 开启。</li><li><strong>原理</strong>：自动为子应用的所有 CSS 规则添加 <code>div[data-qiankun-子应用名]</code> 这样的属性选择器前缀，将其作用域限定在特定容器内。</li><li><strong>代价</strong>：可能因选择器权重增加，或弹窗逃逸出限定容器而产生样式意外。</li></ul></li></ol>`,82),o=[n];function r(i,p,d,c,g,y){return e(),l("div",null,o)}const u=t(a,[["render",r]]);export{f as __pageData,u as default};
